import play.api.mvc._
import javax.inject._

@Singleton
class OrderController @Inject()(val controllerComponents: ControllerComponents,
                               val orderRepository: OrderRepository) extends BaseController {

  def getOrderDetails(id: String): Action[AnyContent] = Action.async {
